fn solve(prices: Vec<i64>, strategy: Vec<i64>, k: i64) -> i64 {
    let n = prices.len() as i64;
    let mut max_profit = 0;

    // Calculate the original profit
    let original_profit: i64 = strategy.iter().zip(prices.iter()).map(|(&s, &p)| s * p).sum();
    max_profit = original_profit;

    // Try modifying each possible window of size k
    let k = k as i64;
    for i in 0..(n - k + 1) {
        let mut modified_strategy = strategy.clone();
        let half = k / 2;

        // Modify the window
        for j in i..i + k {
            if j < i + half {
                modified_strategy[j as usize] = 0;
            } else {
                modified_strategy[j as usize] = 1;
            }
        }

        // Calculate the profit with the modified strategy
        let current_profit: i64 = modified_strategy.iter().zip(prices.iter()).map(|(&s, &p)| s * p).sum();
        if current_profit > max_profit {
            max_profit = current_profit;
        }
    }

    max_profit
}
